import { Component, OnInit } from '@angular/core';
import { CommonModule } from '@angular/common';
import { RouterModule } from '@angular/router';
import { FormsModule } from '@angular/forms';
import { CoursesService } from '../../services';
import { Course, Level, Subject } from '../../models';

@Component({
  selector: 'app-courses',
  standalone: true,
  imports: [CommonModule, RouterModule, FormsModule],
  templateUrl: './courses.component.html',
  styleUrls: ['./courses.component.scss']
})
export class CoursesComponent implements OnInit {
  courses: Course[] = [];
  levels: Level[] = [];
  subjects: Subject[] = [];
  filters = {
    search: '',
    levelId: '',
    subjectId: ''
  };
  loading = true;

  constructor(private coursesService: CoursesService) {}

  ngOnInit() {
    this.loadData();
  }

  loadData() {
    this.loading = true;
    this.coursesService.getLevels().subscribe(levels => {
      this.levels = levels;
    });

    this.coursesService.getSubjects().subscribe(subjects => {
      this.subjects = subjects;
    });

    this.applyFilters();
  }

  applyFilters() {
    this.loading = true;
    this.coursesService.getCourses(this.filters).subscribe(courses => {
      this.courses = courses;
      this.loading = false;
    });
  }

  onFilterChange() {
    this.applyFilters();
  }

  clearFilters() {
    this.filters = {
      search: '',
      levelId: '',
      subjectId: ''
    };
    this.applyFilters();
  }
}
<div class="min-h-screen bg-gray-50 py-8">
  <div class="max-w-7xl mx-auto px-4">
    <!-- Header -->
    <div class="text-center mb-8">
      <h1 class="text-4xl font-bold text-gray-900 mb-4">Course Catalog</h1>
      <p class="text-xl text-gray-600">Discover and enroll in our comprehensive courses</p>
    </div>

    <!-- Filters -->
    <div class="bg-white rounded-lg shadow-md p-6 mb-8">
      <div class="grid md:grid-cols-4 gap-4">
        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Search</label>
          <input 
            type="text" 
            [(ngModel)]="filters.search"
            (ngModelChange)="onFilterChange()"
            placeholder="Search courses..."
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500">
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Level</label>
          <select 
            [(ngModel)]="filters.levelId"
            (ngModelChange)="onFilterChange()"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500">
            <option value="">All Levels</option>
            <option *ngFor="let level of levels" [value]="level.id">{{ level.name }}</option>
          </select>
        </div>

        <div>
          <label class="block text-sm font-medium text-gray-700 mb-2">Subject</label>
          <select 
            [(ngModel)]="filters.subjectId"
            (ngModelChange)="onFilterChange()"
            class="w-full px-3 py-2 border border-gray-300 rounded-md focus:outline-none focus:ring-2 focus:ring-primary-500">
            <option value="">All Subjects</option>
            <option *ngFor="let subject of subjects" [value]="subject.id">{{ subject.name }}</option>
          </select>
        </div>

        <div class="flex items-end">
          <button 
            (click)="clearFilters()"
            class="w-full btn-outline">
            Clear Filters
          </button>
        </div>
      </div>
    </div>

    <!-- Loading State -->
    <div *ngIf="loading" class="grid md:grid-cols-3 gap-6">
      <div *ngFor="let item of [1,2,3,4,5,6]" class="bg-white rounded-lg shadow-md overflow-hidden">
        <div class="loading-skeleton h-48"></div>
        <div class="p-6">
          <div class="loading-skeleton h-4 mb-2"></div>
          <div class="loading-skeleton h-4 mb-4"></div>
          <div class="loading-skeleton h-20 mb-4"></div>
          <div class="loading-skeleton h-10"></div>
        </div>
      </div>
    </div>

    <!-- Course Grid -->
    <div *ngIf="!loading" class="grid md:grid-cols-3 gap-6">
      <div *ngFor="let course of courses" class="bg-white rounded-lg shadow-md overflow-hidden card-hover">
        <img [src]="course.thumbnail || '/api/placeholder/400/200'" 
             [alt]="course.title" 
             class="w-full h-48 object-cover">

        <div class="p-6">
          <div class="flex items-center gap-2 mb-3">
            <span class="px-2 py-1 bg-primary-100 text-primary-600 rounded-full text-xs font-medium">
              {{ course.subjectName }}
            </span>
            <span *ngIf="course.isFree" class="px-2 py-1 bg-green-100 text-green-600 rounded-full text-xs font-medium">
              FREE
            </span>
          </div>

          <h3 class="text-lg font-semibold text-gray-900 mb-2">{{ course.title }}</h3>
          <p class="text-gray-600 mb-4 line-clamp-2">{{ course.description }}</p>

          <div class="flex items-center justify-between mb-4">
            <div class="text-sm text-gray-500">
              <span class="font-medium">{{ course.teacherName }}</span> • {{ course.lessonCount }} lessons
            </div>
            <div class="flex items-center" *ngIf="course.rating">
              <div class="flex text-yellow-400">
                <svg class="w-4 h-4 fill-current" viewBox="0 0 20 20">
                  <path d="M10 15l-5.878 3.09 1.123-6.545L.489 6.91l6.572-.955L10 0l2.939 5.955 6.572.955-4.756 4.635 1.123 6.545z"/>
                </svg>
                <span class="ml-1 text-gray-700">{{ course.rating }}</span>
              </div>
            </div>
          </div>

          <a [routerLink]="['/courses', course.id]" 
             class="w-full btn-gradient text-center block">
            View Course
          </a>
        </div>
      </div>
    </div>

    <!-- Empty State -->
    <div *ngIf="!loading && courses.length === 0" class="text-center py-12">
      <div class="text-gray-400 mb-4">
        <svg class="w-24 h-24 mx-auto" fill="none" stroke="currentColor" viewBox="0 0 24 24">
          <path stroke-linecap="round" stroke-linejoin="round" stroke-width="2" d="M12 6.253v13m0-13C10.832 5.477 9.246 5 7.5 5S4.168 5.477 3 6.253v13C4.168 18.477 5.754 18 7.5 18s3.332-.477 4.5-1.253m0-13C13.168 5.477 14.754 5 16.5 5c1.746 0 3.332.477 4.5 1.253v13C19.832 18.477 18.246 18 16.5 18c-1.746 0-3.332-.477-4.5-1.253"/>
        </svg>
      </div>
      <h3 class="text-xl font-semibold text-gray-900 mb-2">No courses found</h3>
      <p class="text-gray-600 mb-4">Try adjusting your filters or search terms</p>
      <button (click)="clearFilters()" class="btn-gradient">
        Clear Filters
      </button>
    </div>
  </div>
</div>
